CREATE PROC [dbo].[TR_MATERIAL_Update]
( 
	@id         nvarchar(200), 
	@tenvt      nvarchar(max), 
	@mota       nvarchar(max), 
	@quycach    nvarchar(100), 
	@dayy       nvarchar(50), 
	@rong       nvarchar(50), 
	@dai        nvarchar(50), 
	@cao        nvarchar(50), 
	@dacdiem    nvarchar(200), 
	@mausac     nvarchar(100), 
	@dvt        nvarchar(50), 
	@nguyenlieu nvarchar(200), 
	@hinhanh1   nvarchar(max), 
	@ghichu     nvarchar(max), 
	@dobuc      nvarchar(50), 
	@solop      nvarchar(50), 
	@seq10      nvarchar(200), 
	@seq7       nvarchar(100) = NULL, 
	@update_by  nvarchar(50),
	@nhom nvarchar(200) = NULL
)
AS
BEGIN
	DECLARE @xacnhan bit = 1;
	DECLARE @kho nvarchar(200);

	SELECT @kho = kho FROM tr_material
	WHERE id = @id

	IF(@kho = N'BAO BÌ' or @kho = N'HÓA CHẤT' or @kho = N'NGŨ KIM')
	BEGIN
		SET @xacnhan = 0
	END

    UPDATE tr_material
	 SET tenvt = @tenvt, 
		 mota = @mota, 
		 quycach = @quycach, 
		 dayy = @dayy, 
		 rong = @rong, 
		 dai = @dai, 
		 cao = @cao, 
		 dacdiem = @dacdiem, 
		 mausac = @mausac, 
		 dvt = @dvt, 
		 nguyenlieu = @nguyenlieu, 
		 hinhanh1 = CONVERT(varbinary(MAX), @hinhanh1), 
		 ghichu = @ghichu, 
		 dobuc = @dobuc, 
		 solop = @solop, 
		 seq10 = @seq10, 
		 seq7 = @seq7, 
		 update_by = @update_by, 
		 update_date = GETDATE(),
		 xacnhan = @xacnhan,
		 nhom = @nhom
    WHERE  id = @id
END





